/* SQL ID : AsmtDAO.asmtListPaging 설 명 : 과제 목록 페이징 */
SELECT A.* , ROW_NUMBER() OVER(ORDER BY A.ASMT_SBMSN_SDTTM) AS LINE_NO , COUNT(*) OVER() AS TOTAL_CNT , ( SELECT COUNT(T1.ASMT_SBMSN_TRGT_ID) FROM TB_LMS_ASMT_SBMSN_TRGT T1 JOIN TB_LMS_ATNDLC T2 ON T2.USER_ID = T1.USER_ID AND T2.SBJCT_ID = #{sbjctId} WHERE T1.ASMT_ID = A.ASMT_ID AND T2.AUDITYN = 'N' AND T2.ATNDLC_STSCD = 'S' ) AS TRGT_CNT /* 과제 대상자 수*/ , ( SELECT COUNT(T1.ASMT_SBMSN_TRGT_ID) FROM TB_LMS_ASMT_SBMSN_TRGT T1 JOIN TB_LMS_ATNDLC T2 ON T2.USER_ID = T1.USER_ID AND T2.SBJCT_ID = #{sbjctId} WHERE T1.ASMT_ID = A.ASMT_ID AND T2.AUDITYN = 'N' AND T2.ATNDLC_STSCD = 'S' AND EXISTS ( SELECT 1 FROM TB_LMS_ASMT_SBMSN TT1 WHERE TT1.ASMT_ID = A.ASMT_ID AND TT1.USER_ID = T1.USER_ID AND TT1.SBMSN_STSCD IN ( 'SBMSN_CMPTN' , 'SBMSN_RE_CMPTN' , 'SBMSN_DDLN_AFTER' , 'SBMSN_EXTD_PRD' ) AND TT1.DELYN = 'N' ) ) AS SBMSN_CNT /* 과제 제출자 수 */ , ( SELECT COUNT(DISTINCT T1.USER_ID) FROM TB_LMS_ASMT_SBMSN T1 JOIN TB_LMS_ASMT_EVL T2 ON T2.ASMT_SBMSN_ID = T1.ASMT_SBMSN_ID WHERE T1.ASMT_ID = A.ASMT_ID AND T1.SBMSN_STSCD IN ( 'SBMSN_CMPTN' , 'SBMSN_RE_CMPTN' , 'SBMSN_DDLN_AFTER' , 'SBMSN_EXTD_PRD' ) AND T1.DELYN = 'N' AND T2.EVLYN = 'Y' ) AS EVL_CNT /* 평가 수 */ , ( SELECT COUNT(DISTINCT T1.USER_ID) FROM TB_LMS_ASMT_SBMSN T1 WHERE T1.ASMT_ID = A.ASMT_ID AND T1.RESBMSNYN = 'Y' AND T1.DELYN = 'N' ) AS RESBMSN_CNT /* 재제출 수 */ FROM (
) A WHERE 1=1 AND UP_ASMT_ID IS NULL
AND ( LOWER(A.ASMT_TTL) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) )
